def build_naver_blog_context(user_input, places):
    if not NAVER_CLIENT_ID or not NAVER_CLIENT_SECRET:
        return {
            "items": [],
            "text": "[네이버 블로그 검색 결과]\n네이버 블로그 API 키가 없어 블로그 보조 정보를 사용할 수 없습니다.",
        }

    queries = []
    for place in places[:3]:
        place_name = clean_api_text(place.get("place_name"))
        queries.append({"query": f"{place_name} 여행 후기", "keyword": place_name})
    if not queries:
        queries.append({"query": f"{user_input} 경기도 여행 블로그", "keyword": ""})

    lines = ["[네이버 블로그 검색 결과]", "블로그 검색 결과는 후기/분위기 참고용이며, 추천 장소의 기준은 문서 DB입니다."]
    blog_items = []
    seen_links = set()
    found = 0
    last_error = ""

    for query_info in queries[:3]:
        query = query_info["query"]
        keyword = query_info.get("keyword", "")
        result = search_naver_blogs(query, display=2)
        if not result["ok"]:
            last_error = result["error"]
            continue
        for item in result["items"]:
            link = item.get("link", "")
            if link in seen_links:
                continue
            if keyword:
                haystack = clean_api_text(f"{item.get('title', '')} {item.get('description', '')}")
                compact_keyword = re.sub(r"\s+", "", keyword)
                compact_haystack = re.sub(r"\s+", "", haystack)
                region_hits = [region for region in GYEONGGI_REGIONS if region in compact_keyword]
                if compact_keyword not in compact_haystack and not any(region in compact_haystack for region in region_hits):
                    continue
            seen_links.add(link)
            found += 1
            blog_items.append({
                "query": query,
                "title": short_text(item.get("title"), 80),
                "bloggername": short_text(item.get("bloggername"), 40),
                "postdate": item.get("postdate", "정보 없음"),
                "link": link,
                "description": short_text(item.get("description"), 160),
            })
            lines.append(
                f"- 검색어: {query} | 제목: {short_text(item.get('title'), 80)} | "
                f"블로그: {short_text(item.get('bloggername'), 40)} | 날짜: {item.get('postdate', '정보 없음')} | "
                f"링크: {link} | 요약: {short_text(item.get('description'), 160)}"
            )

    if found == 0:
        error_text = f" API 오류: {last_error}" if last_error else ""
        lines.append(f"검색 결과를 가져오지 못했습니다.{error_text}")

    return {"items": blog_items, "text": "\n".join(lines)}


def markdown_link_label(text, fallback="링크"):
    text = clean_api_text(text) or fallback
    return text.replace("[", "(").replace("]", ")")


def build_reference_links(kakao_context, naver_blog_context, meal_context):
    lines = []

    kakao_places = [
        place for place in kakao_context.get("places", [])
        if place.get("place_url")
    ]
    blog_items = [
        item for item in naver_blog_context.get("items", [])
        if item.get("link")
    ]
    restaurants = [
        restaurant for restaurant in meal_context.get("restaurants", [])
        if restaurant.get("place_url")
    ]

    if not kakao_places and not restaurants and not blog_items:
        return ""

    lines.append("### 지도/식사/블로그 링크")

    if kakao_places:
        lines.append("**카카오맵**")
        for place in kakao_places[:6]:
            place_name = markdown_link_label(place.get("place_name"), "장소")
            address = clean_api_text(place.get("road_address_name") or place.get("address_name"))
            address_text = f" - {address}" if address else ""
            lines.append(f"- {place_name}: [카카오맵에서 보기]({place.get('place_url')}){address_text}")

    if restaurants:
        if kakao_places:
            lines.append("")
        lines.append("**가까운 식사 후보**")
        for restaurant in restaurants[:6]:
            place_name = markdown_link_label(restaurant.get("place_name"), "음식점")
            distance = format_distance(restaurant.get("distance_m"))
            anchor = clean_api_text(restaurant.get("anchor_name"))
            address = clean_api_text(restaurant.get("address"))
            detail = f"{anchor} 근처 약 {distance}"
            if address:
                detail += f" - {address}"
            lines.append(f"- {place_name}: [카카오맵에서 보기]({restaurant.get('place_url')}) - {detail}")

    if blog_items:
        if kakao_places or restaurants:
            lines.append("")
        lines.append("**네이버 블로그**")
        for item in blog_items[:4]:
            title = markdown_link_label(item.get("title"), "블로그 글")
            blogger = clean_api_text(item.get("bloggername"))
            postdate = clean_api_text(item.get("postdate"))
            meta = " · ".join(part for part in [blogger, postdate] if part)
            meta_text = f" - {meta}" if meta else ""
            lines.append(f"- [{title}]({item.get('link')}){meta_text}")

    return "\n".join(lines)


def build_reference_bundle(kakao_context, naver_blog_context, meal_context):
    return {
        "places": kakao_context.get("places", []),
        "restaurants": meal_context.get("restaurants", []),
        "blogs": naver_blog_context.get("items", []),
        "markdown": build_reference_links(kakao_context, naver_blog_context, meal_context),
    }


# ────────────────────────────────────────────
# Self-RAG 검색/검증
# ────────────────────────────────────────────
SELF_RAG_RETRIEVAL_K = 6
SELF_RAG_CONTEXT_K = 5


def format_docs_for_self_rag(docs, limit=700):
    if not docs:
        return "문서 없음"
    lines = []
    for idx, doc in enumerate(docs, 1):
        source = doc.metadata.get("source", "출처 정보 없음") if hasattr(doc, "metadata") else "출처 정보 없음"
        page = doc.metadata.get("page") if hasattr(doc, "metadata") else None
        page_text = f", page={page}" if page is not None else ""
        lines.append(f"[문서 {idx} | {source}{page_text}]\n{short_text(doc.page_content, limit)}")
    return "\n\n".join(lines)


def dedupe_docs(docs):
    seen = set()
    unique_docs = []
    for doc in docs:
        key = (
            doc.metadata.get("source", "") if hasattr(doc, "metadata") else "",
            doc.metadata.get("page", "") if hasattr(doc, "metadata") else "",
            short_text(doc.page_content, 160),
        )
        if key in seen:
            continue
        seen.add(key)
        unique_docs.append(doc)
    return unique_docs


def retrieve_candidate_docs(vectorstore, query, destination=None, k=SELF_RAG_RETRIEVAL_K):
    retriever = vectorstore.as_retriever(search_kwargs={"k": k})
    docs = retriever.invoke(query)
    docs = filter_docs_by_destination(docs, destination)
    return dedupe_docs(docs)


def parse_self_rag_grades(raw_text, count):
    grades = {}
    for match in re.finditer(r"(\d+)\s*[\.\):\-]\s*(YES|NO|예|아니오)", raw_text, re.IGNORECASE):
        idx = int(match.group(1)) - 1
        value = match.group(2).lower()
        if 0 <= idx < count:
            grades[idx] = value in ["yes", "예"]
    return grades


def grade_retrieved_docs(llm, user_input, docs, destination=None):
    if not docs:
        return []

    prompt = ChatPromptTemplate.from_template("""당신은 Self-RAG의 문서 관련성 평가자입니다.
사용자 질문에 답하는 데 각 문서가 직접적으로 도움이 되는지 평가하세요.
요청 목적지가 있으면 그 목적지와 맞지 않는 문서는 NO입니다.

[요청 목적지]
{destination}

[사용자 질문]
{question}

[검색 문서]
{documents}

각 줄을 반드시 아래 형식으로만 출력하세요.
1. YES
2. NO
""")
    chain = prompt | llm | StrOutputParser()
    try:
        raw_result = chain.invoke({
            "destination": destination or "목적지 미확인",
            "question": user_input,
            "documents": format_docs_for_self_rag(docs, limit=550),
        })
        grades = parse_self_rag_grades(raw_result, len(docs))
        if not grades:
            return docs[:SELF_RAG_CONTEXT_K]
        relevant_docs = [doc for idx, doc in enumerate(docs) if grades.get(idx, False)]
        return relevant_docs[:SELF_RAG_CONTEXT_K]
    except Exception:
        return docs[:SELF_RAG_CONTEXT_K]


def extract_doc_places_with_coords(docs, destination=None, max_places=4):
    """문서에서 장소명 후보를 추출하고 카카오 좌표를 조회해 반환"""
    candidates = []
    for doc in docs:
        for match in PLACE_SUFFIX_RE.finditer(doc.page_content):
            name = clean_api_text(match.group(1))
            if 2 <= len(name) <= 20 and name not in candidates:
                candidates.append(name)
        if len(candidates) >= max_places * 3:
            break

    places = []
    for name in candidates:
        if len(places) >= max_places:
            break
        place, _ = pick_gyeonggi_place(name, destination=destination)
        if place and place.get("x") and place.get("y"):
            places.append(place)
    return places


def calc_max_route_distance(places):
    """장소 목록에서 임의 두 지점 간 최대 직선거리(km) 반환"""
    if len(places) < 2:
        return 0.0
    max_dist = 0.0
    for i in range(len(places)):
        for j in range(i + 1, len(places)):
            dist = haversine_km(places[i], places[j])
            if dist > max_dist:
                max_dist = dist
    return max_dist


def rewrite_retrieval_query(llm, user_input, destination=None):
    prompt = ChatPromptTemplate.from_template("""당신은 여행 RAG 검색 쿼리 작성자입니다.
사용자 질문을 경기도 여행 문서 DB에서 더 잘 찾을 수 있는 짧은 한국어 검색어로 다시 쓰세요.
요청 목적지가 있으면 반드시 포함하세요. 설명 없이 검색어 한 줄만 출력하세요.

[요청 목적지]
{destination}

[사용자 질문]
{question}

검색어:""")
    chain = prompt | llm | StrOutputParser()
    try:
        rewritten = clean_api_text(chain.invoke({
            "destination": destination or "목적지 미확인",
            "question": user_input,
        }))
        rewritten = rewritten.splitlines()[0].strip(" \"'`")
        if destination and destination not in rewritten:
            rewritten = f"{destination} {rewritten}"
        return rewritten[:180] or user_input
    except Exception:
        return f"{destination or ''} {user_input}".strip()


def self_rag_retrieve_context(llm, vectorstore, user_input, destination=None, transport_mode=None):
    if vectorstore is None:
        return {
            "context": "제공된 문서 데이터가 없습니다.",
            "report": "[Self-RAG 검색 검증]\n문서 DB가 없어 검색 검증을 수행하지 못했습니다.",
            "docs": [],
        }

    initial_query = f"{destination or ''} {user_input}".strip()
    attempts = [{"label": "초기 검색", "query": initial_query}]
    rewritten_query = None

    # 목적지 지정 시 30km, 미지정 시 50km 기준
    if transport_mode == "transit":
        route_threshold_km = 12 if destination else 20
    elif transport_mode == "car":
        route_threshold_km = 25 if destination else 40
    else:
        route_threshold_km = 15 if destination else 30

    # 근접성 검사를 통과하지 못했어도 마지막으로 찾은 문서는 보존
    fallback_docs = []
    fallback_label = ""
    fallback_query = ""

    for attempt_idx, attempt in enumerate(attempts):
        try:
            candidate_docs = retrieve_candidate_docs(
                vectorstore, attempt["query"], destination=destination
            )
        except Exception as exc:
            return {
                "context": f"문서 DB 검색 중 오류가 발생했습니다: {exc}",
                "report": f"[Self-RAG 검색 검증]\n검색 오류: {exc}",
                "docs": [],
            }

        relevant_docs = grade_retrieved_docs(llm, user_input, candidate_docs, destination=destination)

        if not relevant_docs:
            # 관련 문서 없음 → 첫 시도라면 쿼리 재작성 후 재검색
            if attempt_idx == 0:
                rewritten_query = rewrite_retrieval_query(llm, user_input, destination=destination)
                attempts.append({"label": "관련성 재작성 검색", "query": rewritten_query})
            continue

        # ── 동선 근접성 검사 ────────────────────────────────────
        proximity_note = ""
        proximity_passed = True

        if KAKAO_REST_API_KEY:
            doc_places = extract_doc_places_with_coords(relevant_docs, destination=destination)
            max_dist = calc_max_route_distance(doc_places)
            place_names_str = ", ".join(p.get("place_name", "") for p in doc_places[:4])

            if len(doc_places) >= 2 and max_dist > route_threshold_km:
                # 동선이 너무 분산됨 → 재검색 시도
                proximity_passed = False
                proximity_note = (
                    f"\n- 동선 근접성 검사: 장소 간 최대 {max_dist:.1f}km "
                    f"→ 기준({route_threshold_km}km) 초과 ({place_names_str})"
                    "\n- 동선 분산 감지 → 더 밀집된 코스로 재검색합니다."
                )
                # fallback으로 저장해두고, 아직 동선 재검색을 추가하지 않은 경우에만 추가
                fallback_docs = relevant_docs
                fallback_label = attempt["label"]
                fallback_query = attempt["query"]

                if not any(a["label"] == "동선 집중 재검색" for a in attempts):
                    focused_query = rewrite_retrieval_query(
                        llm, user_input, destination=destination
                    )
                    attempts.append({
                        "label": "동선 집중 재검색",
                        "query": focused_query + " 인접 근처",
                    })
            else:
                # 근접성 통과
                if doc_places:
                    proximity_note = (
                        f"\n- 동선 근접성 검사: 통과 "
                        f"(최대 {max_dist:.1f}km, {place_names_str})"
                    )

        if proximity_passed:
            return {
                "context": "\n\n".join(doc.page_content for doc in relevant_docs),
                "report": (
                    "[Self-RAG 검색 검증]\n"
                    f"- {attempt['label']} 쿼리: {attempt['query']}\n"
                    f"- 후보 문서: {len(candidate_docs)}개\n"
                    f"- 관련 문서: {len(relevant_docs)}개\n"
                    "- 관련성이 낮은 문서는 답변 근거에서 제외했습니다."
                    + proximity_note
                ),
                "docs": relevant_docs,
            }
        # 근접성 실패 → 다음 attempt로 (위에서 이미 동선 집중 재검색 추가됨)

    # ── 모든 시도 소진 ────────────────────────────────────────
    # fallback: 근접성 기준 미달이라도 관련 문서가 있으면 사용
    if fallback_docs:
        if destination:
            ctx_note = f"{destination} 내 동선 기준 미달이나 가장 관련성 높은 문서를 사용합니다."
        else:
            ctx_note = "동선 근접성 기준을 완전히 만족하는 문서를 찾지 못해 최선의 결과를 사용합니다."
        return {
            "context": "\n\n".join(doc.page_content for doc in fallback_docs),
            "report": (
                "[Self-RAG 검색 검증]\n"
                f"- 사용 시도: {fallback_label}\n"
                f"- 사용 쿼리: {fallback_query}\n"
                f"- 관련 문서: {len(fallback_docs)}개\n"
                f"- 동선 근접성 재검색 후에도 기준 미달 → fallback 문서 사용\n"
                f"- {ctx_note}"
            ),
            "docs": fallback_docs,
        }

    # 문서 자체를 전혀 못 찾은 경우
    if destination:
        context = f"{destination}와 일치하고 질문에 충분히 관련된 문서 DB 검색 결과가 없습니다. 다른 경기도 시군 장소를 대신 추천하지 마세요."
    else:
        context = "질문에 충분히 관련된 문서 DB 검색 결과가 없습니다. 문서에 없는 장소나 사실을 새로 만들지 마세요."

    return {
        "context": context,
        "report": (
            "[Self-RAG 검색 검증]\n"
            f"- 초기 검색 쿼리: {initial_query}\n"
            f"- 재작성 검색 쿼리: {rewritten_query or '생성 실패'}\n"
            "- 관련 문서를 찾지 못해 답변을 제한해야 합니다."
        ),
        "docs": [],
    }


def parse_yes_no(raw_text):
    text = clean_api_text(raw_text).lower()
    if text.startswith("yes") or text.startswith("예"):
        return True
    if text.startswith("no") or text.startswith("아니오"):
        return False
    return "yes" in text or "예" in text


def self_rag_validate_response(llm, user_input, response, destination, evidence_text):
    prompt = ChatPromptTemplate.from_template("""당신은 Self-RAG의 최종 답변 검증자입니다.
답변이 제공된 근거에 충실하고, 근거에 없는 사실은 모른다고 말하며, 요청 목적지 밖 핵심 장소를 추천하지 않는지 평가하세요.

[요청 목적지]
{destination}

[사용자 질문]
{question}

[근거]
{evidence}

[답변]
{answer}

위 조건을 만족하면 YES, 아니면 NO만 출력하세요.""")
    chain = prompt | llm | StrOutputParser()
    try:
        raw_result = chain.invoke({
            "destination": destination or "목적지 미확인",
            "question": user_input,
            "evidence": short_text(evidence_text, 6500),
            "answer": short_text(response, 4500),
        })
        return parse_yes_no(raw_result)
    except Exception:
        return True


def build_same_destination_history_context(chat_df, current_user_id, user_input, max_examples=3):
    destination = normalize_destination(user_input)
    if chat_df.empty or not destination:
        return {
            "destination": destination or "목적지 미확인",
            "has_examples": False,
            "alternate_mode": wants_alternate_route(user_input),
            "already_recommended": [],
            "text": "[같은 목적지 기존 추천 루틴]\n같은 목적지로 저장된 이전 추천 루틴이 없습니다.",
        }

    rows = chat_df.reset_index(drop=True)
    examples = []

    for idx, row in rows.iterrows():
        if row.get("role") != "user":
            continue
        question = clean_api_text(row.get("content", ""))
        if not destination_matches(question, destination):
            continue

        user_id = str(row.get("user_id", ""))
        answer = ""
        for next_idx in range(idx + 1, min(idx + 5, len(rows))):
            next_row = rows.iloc[next_idx]
            if str(next_row.get("user_id", "")) != user_id:
                continue
            if next_row.get("role") == "assistant":
                answer = clean_api_text(next_row.get("content", ""))
                break
            if next_row.get("role") == "user":
                break

        if not answer:
            continue
        if other_gyeonggi_regions_in_text(answer, destination):
            continue

        examples.append({
            "user_id": user_id,
            "same_user": user_id == str(current_user_id),
            "question": question,
            "answer": short_text(answer, 1200),
            "timestamp": row.get("timestamp", ""),
        })

    if not examples:
        return {
            "destination": destination,
            "has_examples": False,
            "alternate_mode": wants_alternate_route(user_input),
            "already_recommended": [],
            "text": f"[같은 목적지 기존 추천 루틴]\n{destination}로 저장된 이전 추천 루틴이 없습니다.",
        }

    examples = sorted(
        examples,
        key=lambda item: (item["same_user"], str(item.get("timestamp", ""))),
        reverse=True,
    )
    selected = examples[:max_examples]
    alternate_mode = wants_alternate_route(user_input) or any(item["same_user"] for item in selected)

    # 현재 사용자에게 이전에 추천된 장소 추출 (전체 same_user 이력 대상)
    already_recommended = []
    for item in examples:
        if not item["same_user"]:
            continue
        for match in PLACE_SUFFIX_RE.finditer(item["answer"]):
            place = clean_api_text(match.group(1))
            if 2 <= len(place) <= 20 and place not in already_recommended:
                already_recommended.append(place)

    lines = [
        "[같은 목적지 기존 추천 루틴]",
        f"목적지: {destination}",
        f"저장된 유사 루틴: {len(examples)}개",
        f"다른 루틴 요청/필요 여부: {'예' if alternate_mode else '아니오'}",
    ]

    if already_recommended:
        lines.append(f"\n[현재 사용자에게 이미 추천된 장소 - 절대 포함 금지]")
        lines.append("아래 장소들은 현재 사용자에게 이전에 추천한 곳입니다. 같은 목적지 질문 시 핵심 일정에 포함하지 마세요:")
        for place in already_recommended[:15]:
            lines.append(f"- {place}")

    for idx, example in enumerate(selected, 1):
        owner = "현재 사용자" if example["same_user"] else f"다른 사용자 {example['user_id']}"
        lines.append(
            f"\n{idx}. {owner}의 이전 요청: {example['question']}\n"
            f"   이전 추천 요약: {example['answer']}"
        )

    return {
        "destination": destination,
        "has_examples": True,
        "alternate_mode": alternate_mode,
        "already_recommended": already_recommended,
        "text": "\n".join(lines),
    }


def render_leaflet_map(places, restaurants=None):
    """카카오 좌표를 Leaflet.js + OpenStreetMap으로 지도에 표시"""
    if not places:
        return

    place_colors = ["#E74C3C", "#3498DB", "#2ECC71", "#9B59B6", "#1ABC9C", "#E67E22", "#E91E63"]
    place_markers_js = ""
    restaurant_markers_js = ""
    bounds_coords = []
    osrm_coords = []   # OSRM은 "lon,lat" 형식

    # ── 관광지 마커 ───────────────────────────
    for i, place in enumerate(places[:7]):
        try:
            lat = float(place.get("y", 0))
            lon = float(place.get("x", 0))
        except (ValueError, TypeError):
            continue
        name = clean_api_text(place.get("place_name", f"장소 {i+1}")).replace("'", "\\'")
        address = clean_api_text(
            place.get("road_address_name") or place.get("address_name", "")
        ).replace("'", "\\'")
        color = place_colors[i % len(place_colors)]
        bounds_coords.append(f"[{lat}, {lon}]")
        osrm_coords.append(f"{lon},{lat}")
        place_markers_js += f"""
        L.circleMarker([{lat}, {lon}], {{
            radius: 13, fillColor: '{color}',
            color: '#fff', weight: 2.5, fillOpacity: 0.95
        }}).addTo(map)
        .bindPopup('<b>📍 {i+1}. {name}</b><br><small>{address}</small>')
        .bindTooltip('{i+1}', {{permanent: true, direction: 'center',
            className: 'leaflet-num-tooltip'}});
        """

    # ── 음식점 마커 ───────────────────────────
    for r in (restaurants or [])[:6]:
        try:
            lat = float(r.get("y", 0))
            lon = float(r.get("x", 0))
        except (ValueError, TypeError):
            continue
        if not lat or not lon:
            continue
        rname = clean_api_text(r.get("place_name", "음식점")).replace("'", "\\'")
        raddr = clean_api_text(r.get("address", "")).replace("'", "\\'")
        dist  = format_distance(r.get("distance_m"))
        bounds_coords.append(f"[{lat}, {lon}]")
        restaurant_markers_js += f"""
        L.circleMarker([{lat}, {lon}], {{
            radius: 9, fillColor: '#FF9800',
            color: '#fff', weight: 2, fillOpacity: 0.92
        }}).addTo(map)
        .bindPopup('<b>🍽️ {rname}</b><br><small>{raddr}<br>기준 장소에서 약 {dist}</small>');
        """

    center_lat = float(places[0].get("y", 37.5))
    center_lon = float(places[0].get("x", 127.0))
    fit_bounds = (
        f"map.fitBounds([{', '.join(bounds_coords)}], {{padding: [30, 30]}});"
        if len(bounds_coords) >= 2
        else f"map.setView([{center_lat}, {center_lon}], 14);"
    )

    # OSRM 실제 도로 경로 (비동기 fetch, 실패 시 직선 점선 fallback)
    osrm_url = "https://router.project-osrm.org/route/v1/driving/" + ";".join(osrm_coords) + "?geometries=geojson&overview=full"
    fallback_line = (
        f"L.polyline([{', '.join(bounds_coords[:len(osrm_coords)])}], "
        f"{{color:'#FFE033', weight:3, dashArray:'8,5', opacity:0.85}}).addTo(map);"
        if len(osrm_coords) >= 2 else ""
    )

    route_js = ""
    if len(osrm_coords) >= 2:
        route_js = f"""
        var fallbackLine = {fallback_line.rstrip(';')};
        fetch('{osrm_url}')
          .then(r => r.json())
          .then(data => {{
            if (data.code === 'Ok' && data.routes && data.routes[0]) {{
              map.removeLayer(fallbackLine);
              L.geoJSON(data.routes[0].geometry, {{
                style: {{color:'#FFE033', weight:4.5, opacity:0.9, lineCap:'round', lineJoin:'round'}}
              }}).addTo(map);
            }}
          }})
          .catch(() => {{ /* fallback 유지 */ }});
        """
    else:
        route_js = fallback_line

    map_html = f"""<!DOCTYPE html>
<html><head><meta charset="utf-8">
<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"/>
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
<style>
  body {{ margin:0; padding:0; }}
  #map {{ width:100%; height:300px; border-radius:10px; }}
  .leaflet-num-tooltip {{
    background:transparent!important; border:none!important;
    box-shadow:none!important; color:#fff;
    font-weight:700; font-size:12px; padding:0;
  }}
  .leaflet-popup-content {{ font-size:12px; line-height:1.5; }}
</style>
</head><body>
<div id="map"></div>
<script>
  var map = L.map('map', {{zoomControl:true, attributionControl:false}})
             .setView([{center_lat}, {center_lon}], 13);
  L.tileLayer('https://tile.openstreetmap.org/{{z}}/{{x}}/{{y}}.png', {{maxZoom:19}}).addTo(map);

  // 범례
  var legend = L.control({{position:'bottomright'}});
  legend.onAdd = function() {{
    var d = L.DomUtil.create('div','');
    d.style.cssText='background:white;padding:6px 8px;border-radius:6px;font-size:11px;line-height:1.6';
    d.innerHTML='<b style="font-size:12px">범례</b><br>'
      +'<span style="color:#E74C3C">●</span> 관광지<br>'
      +'<span style="color:#FF9800">●</span> 음식점<br>'
      +'<span style="color:#FFE033;font-weight:700">━</span> 이동경로';
    return d;
  }};
  legend.addTo(map);

  {route_js}
  {place_markers_js}
  {restaurant_markers_js}
  {fit_bounds}
</script>

</script>
</body></html>"""

    components.html(map_html, height=312)




def save_favorite(user_id, content):
    """여행 계획을 즐겨찾기에 저장"""
    # 경기도 지역명 추출해서 제목 생성
    import re as _re
    region_found = None
    for region in GYEONGGI_REGIONS:
        if region in content:
            region_found = region
            break
    # 1박2일, 당일치기 등 일정 유형 추출
    schedule_type = ""
    if "1박2일" in content or "1박 2일" in content:
        schedule_type = " 1박2일"
    elif "2박3일" in content or "2박 3일" in content:
        schedule_type = " 2박3일"
    elif "당일치기" in content:
        schedule_type = " 당일치기"
    if region_found:
        title = f"{region_found}{schedule_type} 여행"
    else:
        lines = [l.strip() for l in content.strip().split("\n") if l.strip()]
        title = lines[0].lstrip("#").strip()[:30] if lines else "여행 계획"
    new_row = pd.DataFrame([{
        "user_id": str(user_id),
        "title": title,
        "content": content,
        "saved_at": datetime.now().strftime("%Y-%m-%d %H:%M")
    }])
    new_row.to_csv(FAVORITES_FILE, mode="a", header=False, index=False)

def load_favorites(user_id):
    """사용자의 즐겨찾기 목록 로드"""
    if not os.path.exists(FAVORITES_FILE):
        return pd.DataFrame(columns=["user_id", "title", "content", "saved_at"])
    df = pd.read_csv(FAVORITES_FILE, dtype={"user_id": str})
    return df[df["user_id"] == str(user_id)].reset_index(drop=True)

def delete_favorite(user_id, idx):
    """즐겨찾기 항목 삭제"""
    df = pd.read_csv(FAVORITES_FILE, dtype={"user_id": str})
    user_df = df[df["user_id"] == str(user_id)].reset_index()
    if idx < len(user_df):
        original_idx = user_df.loc[idx, "index"]
        df = df.drop(original_idx).reset_index(drop=True)
        df.to_csv(FAVORITES_FILE, index=False)

@st.dialog("여행 동선 지도", width="large")
def show_fullscreen_map(places, restaurants):
    """전체화면 지도 모달"""
    # 지도를 더 크게 렌더링
    if not places:
        st.info("표시할 장소가 없습니다.")
        return

    place_colors = ["#E74C3C", "#3498DB", "#2ECC71", "#9B59B6", "#1ABC9C", "#E67E22", "#E91E63"]
    place_markers_js = ""
    restaurant_markers_js = ""
    bounds_coords = []
    osrm_coords = []

    for i, place in enumerate(places[:7]):
        try:
            lat = float(place.get("y", 0))
            lon = float(place.get("x", 0))
        except (ValueError, TypeError):
            continue
        name = clean_api_text(place.get("place_name", f"장소 {i+1}")).replace("'", "\\'")
        address = clean_api_text(place.get("road_address_name") or place.get("address_name", "")).replace("'", "\\'")
        color = place_colors[i % len(place_colors)]
        bounds_coords.append(f"[{lat}, {lon}]")
        osrm_coords.append(f"{lon},{lat}")
        place_markers_js += f"""
        L.circleMarker([{lat}, {lon}], {{
            radius: 16, fillColor: '{color}',
            color: '#fff', weight: 2.5, fillOpacity: 0.95
        }}).addTo(map)
        .bindPopup('<b>📍 {i+1}. {name}</b><br><small>{address}</small>')
        .bindTooltip('{i+1}', {{permanent: true, direction: 'center',
            className: 'leaflet-num-tooltip'}});
        """

    for r in (restaurants or [])[:6]:
        try:
            lat = float(r.get("y", 0))
            lon = float(r.get("x", 0))
        except (ValueError, TypeError):
            continue
        if not lat or not lon:
            continue
        rname = clean_api_text(r.get("place_name", "음식점")).replace("'", "\\'")
        raddr = clean_api_text(r.get("address", "")).replace("'", "\\'")
        dist = format_distance(r.get("distance_m"))
        bounds_coords.append(f"[{lat}, {lon}]")
        restaurant_markers_js += f"""
        L.circleMarker([{lat}, {lon}], {{
            radius: 11, fillColor: '#FF9800',
            color: '#fff', weight: 2, fillOpacity: 0.92
        }}).addTo(map)
        .bindPopup('<b>🍽️ {rname}</b><br><small>{raddr}<br>약 {dist}</small>');
        """

    center_lat = float(places[0].get("y", 37.5))
    center_lon = float(places[0].get("x", 127.0))
    fit_bounds = (
        f"map.fitBounds([{', '.join(bounds_coords)}], {{padding: [40, 40]}});"
        if len(bounds_coords) >= 2
        else f"map.setView([{center_lat}, {center_lon}], 14);"
    )

    osrm_url = "https://router.project-osrm.org/route/v1/driving/" + ";".join(osrm_coords) + "?geometries=geojson&overview=full"
    fallback_line = (
        f"L.polyline([{', '.join(bounds_coords[:len(osrm_coords)])}], "
        f"{{color:'#FFE033', weight:4, dashArray:'8,5', opacity:0.85}}).addTo(map);"
        if len(osrm_coords) >= 2 else ""
    )
    route_js = ""
    if len(osrm_coords) >= 2:
        route_js = f"""
        var fallbackLine = {fallback_line.rstrip(';')};
        fetch('{osrm_url}')
          .then(r => r.json())
          .then(data => {{
            if (data.code === 'Ok' && data.routes && data.routes[0]) {{
              map.removeLayer(fallbackLine);
              L.geoJSON(data.routes[0].geometry, {{
                style: {{color:'#FFE033', weight:5, opacity:0.9}}
              }}).addTo(map);
            }}
          }}).catch(() => {{}});
        """
    else:
        route_js = fallback_line

    map_html = f"""<!DOCTYPE html>
<html><head><meta charset="utf-8">
<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"/>
<script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script>
<style>
  body {{ margin:0; padding:0; }}
  #map {{ width:100%; height:600px; border-radius:10px; }}
  .leaflet-num-tooltip {{
    background:transparent!important; border:none!important;
    box-shadow:none!important; color:#fff;
    font-weight:700; font-size:14px; padding:0;
  }}
  .leaflet-popup-content {{ font-size:14px; line-height:1.5; }}
</style>
</head><body>
<div id="map"></div>
<script>
  var map = L.map('map', {{zoomControl:true, attributionControl:false}})
             .setView([{center_lat}, {center_lon}], 13);
  L.tileLayer('https://tile.openstreetmap.org/{{z}}/{{x}}/{{y}}.png', {{maxZoom:19}}).addTo(map);
  var legend = L.control({{position:'bottomright'}});
  legend.onAdd = function() {{
    var d = L.DomUtil.create('div','');
    d.style.cssText='background:white;padding:8px 10px;border-radius:8px;font-size:13px;line-height:1.8';
    d.innerHTML='<b>범례</b><br><span style="color:#E74C3C">●</span> 관광지<br><span style="color:#FF9800">●</span> 음식점<br><span style="color:#FFE033;font-weight:700">━</span> 이동경로';
    return d;
  }};
  legend.addTo(map);
  {route_js}
  {place_markers_js}
  {restaurant_markers_js}
  {fit_bounds}
</script>
</body></html>"""

    components.html(map_html, height=620)

def render_reference_panel(references):
    st.markdown("### 추가 정보")
    if not references or not references.get("markdown"):
        st.info("새 여행 일정을 요청하면 여기에 카카오맵 주소, 가까운 식사 후보, 블로그 링크가 표시됩니다.")
        return

    places = references.get("places", [])
    restaurants = references.get("restaurants", [])
    blogs = references.get("blogs", [])

    map_tab, meal_tab, blog_tab = st.tabs(["지도", "식사", "블로그"])

    with map_tab:
        if not places:
            st.caption("카카오맵 장소 링크가 없습니다.")
        else:
            # ── 실제 지도 임베딩 ──
            render_leaflet_map(places, restaurants=restaurants)
            if st.button("크게 보기", key="fullscreen_map_btn", use_container_width=True):
                show_fullscreen_map(places, restaurants)
            st.markdown("<br>", unsafe_allow_html=True)
            for place in places[:8]:
                name = clean_api_text(place.get("place_name"))
                address = clean_api_text(place.get("road_address_name") or place.get("address_name"))
                st.markdown(f"**{name}**")
                if address:
                    st.caption(address)
                st.markdown(f"[카카오맵에서 보기]({place.get('place_url')})")
                st.divider()

    with meal_tab:
        if not restaurants:
            st.caption("가까운 식사 후보가 없습니다.")
        for restaurant in restaurants[:8]:
            name = clean_api_text(restaurant.get("place_name"))
            anchor = clean_api_text(restaurant.get("anchor_name"))
            distance = format_distance(restaurant.get("distance_m"))
            address = clean_api_text(restaurant.get("address"))
            st.markdown(f"**{name}**")
            st.caption(f"{anchor} 근처 약 {distance}")
            if address:
                st.caption(address)
            st.markdown(f"[카카오맵에서 보기]({restaurant.get('place_url')})")
            st.divider()

    with blog_tab:
        if not blogs:
            st.caption("네이버 블로그 링크가 없습니다.")
        for blog in blogs[:6]:
            title = markdown_link_label(blog.get("title"), "블로그 글")
            blogger = clean_api_text(blog.get("bloggername"))
            postdate = clean_api_text(blog.get("postdate"))
            meta = " · ".join(part for part in [blogger, postdate] if part)
            st.markdown(f"**[{title}]({blog.get('link')})**")
            if meta:
                st.caption(meta)
            description = clean_api_text(blog.get("description"))
            if description:
                st.caption(description)
            st.divider()

