        # ── 대중교통/자차 답변 처리 (pending 상태일 때) ──
        if st.session_state.pending_itinerary:
            original_request = st.session_state.pending_itinerary
            st.session_state.pending_itinerary = None
            transport_label = {"car": "자차", "transit": "대중교통"}.get(
                st.session_state.transport_mode, None
            )
            actual_prompt = (
                f"{original_request} (이동 수단: {transport_label})"
                if transport_label else original_request
            )
            with st.chat_message("assistant"):
                with st.spinner("여행 일정을 만들고 있어요..."):
                    response, references = get_ai_response(
                        st.session_state.user_id,
                        st.session_state.preferences,
                        actual_prompt,
                        vectorstore,
                        transport_mode=st.session_state.transport_mode,
                        pure_llm_mode=st.session_state.pure_llm_mode,
                    )
                st.session_state.latest_references = references
                st.markdown(response)
            st.session_state.messages.append({"role": "assistant", "content": response})
            st.rerun()

        # ── 일정 요청인데 교통수단 미확인 → 질문 ──
        elif is_itinerary_request(prompt) and not st.session_state.transport_mode:
            st.session_state.pending_itinerary = prompt
            clarify_msg = (
                "자차로 이동하실 건가요, 대중교통을 이용하실 건가요? 🚗🚌\n"
                "이동 수단에 따라 동선 범위와 이동 시간 안내가 달라져요!"
            )
            with st.chat_message("assistant"):
                st.markdown(clarify_msg)
            pd.DataFrame([
                {"user_id": str(st.session_state.user_id), "role": "user", "content": prompt, "timestamp": datetime.now()},
                {"user_id": str(st.session_state.user_id), "role": "assistant", "content": clarify_msg, "timestamp": datetime.now()},
            ]).to_csv(CHAT_FILE, mode="a", header=False, index=False)
            st.session_state.messages.append({"role": "assistant", "content": clarify_msg})
            st.rerun()

        # ── 일반 흐름 (교통수단 있거나 일정 요청 아님) ──
        else:
            with st.chat_message("assistant"):
                with st.spinner("여행 일정을 만들고 있어요..."):
                    response, references = get_ai_response(
                        st.session_state.user_id,
                        st.session_state.preferences,
                        prompt,
                        vectorstore,
                        transport_mode=st.session_state.transport_mode,
                        pure_llm_mode=st.session_state.pure_llm_mode,
                    )
                st.session_state.latest_references = references
                st.markdown(response)
            st.session_state.messages.append({"role": "assistant", "content": response})
            st.rerun()
